package com.pos;
import javax.swing.*; import javax.swing.table.DefaultTableModel; import java.awt.*; import java.sql.*; import java.util.*;
public class PosCheckoutPanel extends JPanel { private final UserSession s; private final JTextField productSearch=new JTextField(18),qty=new JTextField("1",5),customerId=new JTextField(6),terminalId=new JTextField("1",5),shiftId=new JTextField(6),tendered=new JTextField("0",10); private final JComboBox<String> method=new JComboBox<String>(new String[]{"CASH","GCASH","CARD","BANK_TRANSFER"}); private final QueryTableModel productModel=new QueryTableModel(); private final JTable products=new JTable(productModel); private final DefaultTableModel cartModel=new DefaultTableModel(new Object[]{"Product ID","Product","Qty","Unit Price","With Tax"},0); private final JTable cart=new JTable(cartModel);
 public PosCheckoutPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel head=new JPanel(new BorderLayout());head.add(UIUtils.title("POS Counter Checkout"),BorderLayout.WEST);JPanel find=new JPanel();find.add(new JLabel("Product/Barcode:"));find.add(productSearch);JButton search=new JButton("Search"),all=new JButton("Refresh");find.add(search);find.add(all);head.add(find,BorderLayout.EAST);add(head,BorderLayout.NORTH);JSplitPane split=new JSplitPane(JSplitPane.VERTICAL_SPLIT,new JScrollPane(products),new JScrollPane(cart));split.setResizeWeight(.55);add(split,BorderLayout.CENTER);JPanel action=new JPanel();action.setBorder(BorderFactory.createTitledBorder("Checkout"));action.add(new JLabel("Qty"));action.add(qty);JButton add=new JButton("Add Selected"),remove=new JButton("Remove"),clear=new JButton("Clear");action.add(add);action.add(remove);action.add(clear);action.add(new JLabel("Customer ID optional"));action.add(customerId);action.add(new JLabel("Terminal"));action.add(terminalId);action.add(new JLabel("Shift ID"));action.add(shiftId);action.add(method);action.add(new JLabel("Tendered"));action.add(tendered);JButton pay=new JButton("Complete Sale / Print Receipt");action.add(pay);add(action,BorderLayout.SOUTH);search.addActionListener(e->search());all.addActionListener(e->load());add.addActionListener(e->addLine());remove.addActionListener(e->{int r=cart.getSelectedRow();if(r>=0)cartModel.removeRow(r);});clear.addActionListener(e->cartModel.setRowCount(0));pay.addActionListener(e->checkout());load();}
 private void load(){try{productModel.load("SELECT p.product_id,p.sku,p.product_name,b.barcode,p.selling_price,COALESCE(SUM(sb.quantity_on_hand),0) available FROM products p LEFT JOIN product_barcodes b ON b.product_id=p.product_id AND b.is_primary=1 LEFT JOIN stock_balances sb ON sb.product_id=p.product_id WHERE p.status='ACTIVE' GROUP BY p.product_id,p.sku,p.product_name,b.barcode,p.selling_price ORDER BY p.product_name");}catch(Exception e){UIUtils.error(this,e);}}
 private void search(){try{productModel.load("SELECT p.product_id,p.sku,p.product_name,b.barcode,p.selling_price,COALESCE(SUM(sb.quantity_on_hand),0) available FROM products p LEFT JOIN product_barcodes b ON b.product_id=p.product_id AND b.is_primary=1 LEFT JOIN stock_balances sb ON sb.product_id=p.product_id WHERE p.status='ACTIVE' AND (p.product_name LIKE ? OR p.sku LIKE ? OR b.barcode LIKE ?) GROUP BY p.product_id,p.sku,p.product_name,b.barcode,p.selling_price ORDER BY p.product_name","%"+productSearch.getText()+"%","%"+productSearch.getText()+"%","%"+productSearch.getText()+"%");}catch(Exception e){UIUtils.error(this,e);}}
 private void addLine(){int row=products.getSelectedRow();if(row<0){UIUtils.info(this,"Select a product.");return;}try{row=products.convertRowIndexToModel(row);int id=Integer.parseInt(String.valueOf(productModel.getValueAt(row,0)));String n=String.valueOf(productModel.getValueAt(row,2));double p=Double.parseDouble(String.valueOf(productModel.getValueAt(row,4)));double q=Double.parseDouble(qty.getText());double available=Double.parseDouble(String.valueOf(productModel.getValueAt(row,5)));if(q<=0||available<q)throw new Exception("Invalid quantity or insufficient stock.");cartModel.addRow(new Object[]{id,n,q,p,q*p*(1+AppConstants.TAX_RATE)});}catch(Exception e){UIUtils.error(this,e);}}
 private void checkout(){try{java.util.List<POSService.CartLine> items=new ArrayList<POSService.CartLine>();for(int i=0;i<cartModel.getRowCount();i++)items.add(new POSService.CartLine(Integer.parseInt(String.valueOf(cartModel.getValueAt(i,0))),String.valueOf(cartModel.getValueAt(i,1)),Double.parseDouble(String.valueOf(cartModel.getValueAt(i,2))),Double.parseDouble(String.valueOf(cartModel.getValueAt(i,3)))));Integer cid=customerId.getText().trim().isEmpty()?null:Integer.valueOf(customerId.getText().trim());Integer sid=shiftId.getText().trim().isEmpty()?null:Integer.valueOf(shiftId.getText().trim());int order=POSService.createSale(cid,s.userId,Integer.parseInt(terminalId.getText()),sid,"POS",String.valueOf(method.getSelectedItem()),Double.parseDouble(tendered.getText()),items);Audit.log(s,"POS_SALE","order_id="+order);cartModel.setRowCount(0);load();UIUtils.info(this,"Sale completed. Receipt created for Order ID: "+order);}catch(Exception e){UIUtils.error(this,e);}}
}
